Bash(powershell -Command "
\\$headers = @{
  'expo-runtime-version' = '1.1.0'
  'expo-channel-name' = 'production'
  'expo-platform' = 'ios'
  'expo-protocol-version' = '1'
}
try {
  \\$r = Invoke-WebRequest -Uri 'https://u.expo.dev/6bb9b696-be28-40e8-a06b-dda93652e07c' -Headers \\$headers -MaximumRedirection 0 -ErrorAction SilentlyContinue
  Write-Output \('Status: ' + \\$r.StatusCode\)
  Write-Output \\$r.Content.Substring\(0, [Math]::Min\(500, \\$r.Content.Length\)\)
} catch {
  \\$resp = \\$_.Exception.Response
  if \(\\$resp\) {
    Write-Output \('Status: ' + [int]\\$resp.StatusCode\)
  }
  Write-Output \\$_.Exception.Message
}
")
